unit lipdecide;

interface

uses
  globals;

function REALCOMPARE(A, B : real) : COMPTYPE;
function Distance(x1, y1, x2, y2: real): real;
function TriangleArea(x1, y1, x2, y2, x3, y3: real): real;
function GetAngle(x1, y1, x2, y2, x3, y3: real): real;
function GetQuadrant(x, y: real): integer;
function Circumradius(x1, y1, x2, y2, x3, y3: real): real;
function PointToLineSegmentDistance(px, py, x1, y1, x2, y2: real): real;

procedure DECIDE;

implementation

const
  EPSILON_REAL_COMPARE = 1e-7; // Tolerance for REALCOMPARE
  LARGE_NUMBER = 1e30;        // For representing infinity in circumradius calculation
  PI_CONST = PI;              // Use global PI from globals unit

{-----------------------------------------------------------------------------}
{ REALCOMPARE compares two real numbers with respect to the six most significant digits. }
{-----------------------------------------------------------------------------}
function REALCOMPARE(A, B : real) : COMPTYPE;
begin
  if abs(A - B) < EPSILON_REAL_COMPARE then
    REALCOMPARE := EQ
  else if A < B then
    REALCOMPARE := LT
  else
    REALCOMPARE := GT;
end;

{-----------------------------------------------------------------------------}
{ Helper function to calculate distance between two points. }
{-----------------------------------------------------------------------------}
function Distance(x1, y1, x2, y2: real): real;
var
  dx, dy: real;
begin
  dx := x2 - x1;
  dy := y2 - y1;
  Distance := sqrt(dx*dx + dy*dy);
end;

{-----------------------------------------------------------------------------}
{ Helper function to calculate the area of a triangle using coordinates. }
{-----------------------------------------------------------------------------}
function TriangleArea(x1, y1, x2, y2, x3, y3: real): real;
begin
  TriangleArea := 0.5 * abs(x1*(y2-y3) + x2*(y3-y1) + x3*(y1-y2));
end;

{-----------------------------------------------------------------------------}
{ Helper function to calculate the angle (in radians) at vertex P2 formed by P1-P2-P3. }
{ Returns -1 if the angle is undefined (e.g., coincident points at vertex). }
{-----------------------------------------------------------------------------}
function GetAngle(x1, y1, x2, y2, x3, y3: real): real;
var
  v1x, v1y, v2x, v2y: real;
  mag1, mag2, dot_product, cos_angle: real;
begin
  // Check for coincident points at the vertex
  if (x1 = x2) and (y1 = y2) then begin
    GetAngle := -1.0; // Indicate undefined angle
    exit;
  end;
  if (x3 = x2) and (y3 = y2) then begin
    GetAngle := -1.0; // Indicate undefined angle
    exit;
  end;

  // Vectors from vertex (x2, y2) to P1 and P3
  v1x := x1 - x2;
  v1y := y1 - y2;
  v2x := x3 - x2;
  v2y := y3 - y2;

  mag1 := sqrt(v1x*v1x + v1y*v1y);
  mag2 := sqrt(v2x*v2x + v2y*v2y);

  // If either magnitude is zero, points are coincident (should be caught above, but safety check)
  if (mag1 < EPSILON_REAL_COMPARE) or (mag2 < EPSILON_REAL_COMPARE) then begin
    GetAngle := -1.0; // Undefined
    exit;
  end;

  dot_product := v1x * v2x + v1y * v2y;
  cos_angle := dot_product / (mag1 * mag2);

  // Clamp cos_angle to [-1, 1] to avoid issues with acos due to floating point inaccuracies
  if cos_angle > 1.0 then cos_angle := 1.0
  else if cos_angle < -1.0 then cos_angle := -1.0;

  GetAngle := acos(cos_angle);
end;

{-----------------------------------------------------------------------------}
{ Helper function to determine the quadrant of a point (x, y). }
{ Uses specific rules from the spec for points on axes and the origin. }
{-----------------------------------------------------------------------------}
function GetQuadrant(x, y: real): integer;
begin
  if y > 0 then begin
    if x >= 0 then GetQuadrant := 1 // Q1 (includes positive y-axis)
    else GetQuadrant := 2; // Q2 (negative x, positive y)
  end else if y < 0 then begin
    if x <= 0 then GetQuadrant := 3 // Q3 (includes negative y-axis)
    else GetQuadrant := 4; // Q4 (positive x, negative y)
  end else begin // y = 0
    if x >= 0 then GetQuadrant := 1 // Q1 (includes positive x-axis and origin)
    else GetQuadrant := 2; // Q2 (negative x-axis)
  end;
end;

{-----------------------------------------------------------------------------}
{ Helper function to calculate the circumradius of a triangle. }
{ Returns a very large number (LARGE_NUMBER) if points are collinear or coincident, }
{ indicating they cannot be contained in a finite circle. }
{-----------------------------------------------------------------------------}
function Circumradius(x1, y1, x2, y2, x3, y3: real): real;
var
  a, b, c, area: real;
begin
  a := Distance(x2, y2, x3, y3); // side opposite P1
  b := Distance(x1, y1, x3, y3); // side opposite P2
  c := Distance(x1, y1, x2, y2); // side opposite P3
  area := TriangleArea(x1, y1, x2, y2, x3, y3);

  // If points are collinear or coincident, area is near zero.
  if area < EPSILON_REAL_COMPARE then begin
    // If all points are coincident, they are contained in any circle.
    if (a < EPSILON_REAL_COMPARE) and (b < EPSILON_REAL_COMPARE) then
      Circumradius := 0.0
    else
      // If collinear and not all coincident, circumradius is effectively infinite.
      Circumradius := LARGE_NUMBER;
  end else begin
    Circumradius := (a * b * c) / (4.0 * area);
  end;
end;

{-----------------------------------------------------------------------------}
{ Helper function to calculate the distance from a point (px, py) to a line segment (x1, y1) to (x2, y2). }
{-----------------------------------------------------------------------------}
function PointToLineSegmentDistance(px, py, x1, y1, x2, y2: real): real;
var
  line_len_sq, t, dist_point_to_line: real;
  closest_x, closest_y: real;
begin
  line_len_sq := (x2 - x1)*(x2 - x1) + (y2 - y1)*(y2 - y1);

  if line_len_sq < EPSILON_REAL_COMPARE then begin // Segment is a point
    PointToLineSegmentDistance := Distance(px, py, x1, y1);
    exit;
  end;

  // Calculate projection of point P onto the line defined by the segment
  t := ((px - x1) * (x2 - x1) + (py - y1) * (y2 - y1)) / line_len_sq;

  // Clamp t to [0, 1] to find the closest point on the segment
  if t < 0.0 then begin
    closest_x := x1;
    closest_y := y1;
  end else if t > 1.0 then begin
    closest_x := x2;
    closest_y := y2;
  end else begin
    closest_x := x1 + t * (x2 - x1);
    closest_y := y1 + t * (y2 - y1);
  end;

  PointToLineSegmentDistance := Distance(px, py, closest_x, closest_y);
end;


{-----------------------------------------------------------------------------}
{ DECIDE procedure implementation.                                           }
{ Reads inputs from and writes outputs to globals.                            }
{-----------------------------------------------------------------------------}
procedure DECIDE;
var
  i, j, k, q, quad_idx, num_quads_used: integer;
  p1_x, p1_y, p2_x, p2_y, p3_x, p3_y: real;
  dist, angle, area, circum_r, line_dist: real;
  row_all_true: boolean;
  current_quadrants: array[1..4] of integer;

begin
  // Initialize PUM and FUV, CMV - Assuming globals unit provides them.
  // CMV will be set per LIC.
  // PUM and FUV need to be fully computed after all CMV are set.
  // LAUNCH is the final output.

  // --- Compute CMV (Conditions Met Vector) ---

  // LIC 1: Two consecutive points distance > LENGTH1
  CMV[1] := false;
  for i := 1 to NUMPOINTS - 1 do
  begin
    dist := Distance(X[i], Y[i], X[i+1], Y[i+1]);
    if dist > PARAMETERS.LENGTH1 then
    begin
      CMV[1] := true;
      break;
    end;
  end;

  // LIC 2: Three consecutive points not all contained within or on a circle of radius RADIUS1.
  CMV[2] := false;
  if NUMPOINTS >= 3 then
    for i := 1 to NUMPOINTS - 2 do
    begin
      circum_r := Circumradius(X[i], Y[i], X[i+1], Y[i+1], X[i+2], Y[i+2]);
      if circum_r > PARAMETERS.RADIUS1 then
      begin
        CMV[2] := true;
        break;
      end;
    end;

  // LIC 3: Three consecutive points form an angle < (PI - EPSILON) or > (PI + EPSILON).
  CMV[3] := false;
  if NUMPOINTS >= 3 then
    for i := 1 to NUMPOINTS - 2 do
    begin
      angle := GetAngle(X[i], Y[i], X[i+1], Y[i+1], X[i+2], Y[i+2]);
      if (angle >= 0) and ((angle < PI_CONST - PARAMETERS.EPSILON) or (angle > PI_CONST + PARAMETERS.EPSILON)) then
      begin
        CMV[3] := true;
        break;
      end;
    end;

  // LIC 4: Three consecutive points form a triangle with area > AREA1.
  CMV[4] := false;
  if NUMPOINTS >= 3 then
    for i := 1 to NUMPOINTS - 2 do
    begin
      area := TriangleArea(X[i], Y[i], X[i+1], Y[i+1], X[i+2], Y[i+2]);
      if area > PARAMETERS.AREA1 then
      begin
        CMV[4] := true;
        break;
      end;
    end;

  // LIC 5: Q_PTS consecutive points lie in more than QUADS quadrants.
  CMV[5] := false;
  if NUMPOINTS >= PARAMETERS.Q_PTS then
    for i := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
    begin
      // Initialize quadrant counts for the current set of points
      for q := 1 to 4 do
        current_quadrants[q] := 0;

      // Count points in each quadrant for the current segment
      for j := i to i + PARAMETERS.Q_PTS - 1 do
      begin
        quad_idx := GetQuadrant(X[j], Y[j]);
        current_quadrants[quad_idx] := current_quadrants[quad_idx] + 1;
      end;

      // Count how many quadrants were used
      num_quads_used := 0;
      for q := 1 to 4 do
        if current_quadrants[q] > 0 then
          num_quads_used := num_quads_used + 1;

      if num_quads_used > PARAMETERS.QUADS then
      begin
        CMV[5] := true;
        break;
      end;
    end;

  // LIC 6: Two consecutive points (X[i], Y[i]) and (X[j], Y[j]) with X[j] - X[i] < 0.
  CMV[6] := false;
  for i := 1 to NUMPOINTS - 1 do
  begin
    if X[i+1] < X[i] then
    begin
      CMV[6] := true;
      break;
    end;
  end;

  // LIC 7: N_PTS consecutive points, at least one point > DIST from line joining first and last.
  CMV[7] := false;
  if NUMPOINTS >= 3 then
    for i := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
    begin
      p1_x := X[i];
      p1_y := Y[i];
      p2_x := X[i + PARAMETERS.N_PTS - 1];
      p2_y := Y[i + PARAMETERS.N_PTS - 1];

      // Check if endpoints are distinct enough to form a line
      if Distance(p1_x, p1_y, p2_x, p2_y) < EPSILON_REAL_COMPARE then begin
          // Endpoints are coincident or very close, treat as a single point
          for k := i + 1 to i + PARAMETERS.N_PTS - 2 do begin
            if Distance(X[k], Y[k], p1_x, p1_y) > PARAMETERS.DIST then begin
              CMV[7] := true;
              break;
            end;
          end;
      end else begin
          // Endpoints are distinct, calculate distance to line segment
          for k := i + 1 to i + PARAMETERS.N_PTS - 2 do begin
            line_dist := PointToLineSegmentDistance(X[k], Y[k], p1_x, p1_y, p2_x, p2_y);
            if line_dist > PARAMETERS.DIST then begin
              CMV[7] := true;
              break;
            end;
          end;
      end;
      if CMV[7] then break;
    end;

  // LIC 8: Two points separated by K_PTS points, distance > LENGTH1.
  CMV[8] := false;
  if NUMPOINTS >= 3 then // K_PTS >= 1, so requires at least 1 + 1 + 1 = 3 points
    for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 2 do
    begin
      dist := Distance(X[i], Y[i], X[i + PARAMETERS.K_PTS + 1], Y[i + PARAMETERS.K_PTS + 1]);
      if dist > PARAMETERS.LENGTH1 then
      begin
        CMV[8] := true;
        break;
      end;
    end;

  // LIC 9: Three points separated by A_PTS and B_PTS, cannot be contained in circle of radius RADIUS1.
  CMV[9] := false;
  if NUMPOINTS >= 5 then // A_PTS >= 1, B_PTS >= 1, A_PTS + B_PTS <= NUMPOINTS - 3. Min: 1+1 <= NUMPOINTS-3 => NUMPOINTS >= 5
    for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 3 do
    begin
      p1_x := X[i];
      p1_y := Y[i];
      p2_x := X[i + PARAMETERS.A_PTS + 1];
      p2_y := Y[i + PARAMETERS.A_PTS + 1];
      p3_x := X[i + PARAMETERS.A_PTS + 1 + PARAMETERS.B_PTS + 1];
      p3_y := Y[i + PARAMETERS.A_PTS + 1 + PARAMETERS.B_PTS + 1];

      circum_r := Circumradius(p1_x, p1_y, p2_x, p2_y, p3_x, p3_y);
      if circum_r > PARAMETERS.RADIUS1 then
      begin
        CMV[9] := true;
        break;
      end;
    end;

  // LIC 10: Three points separated by C_PTS and D_PTS, form angle < (PI - EPSILON) or > (PI + EPSILON).
  CMV[10] := false;
  if NUMPOINTS >= 5 then // C_PTS >= 1, D_PTS >= 1, C_PTS + D_PTS <= NUMPOINTS - 3. Min: 1+1 <= NUMPOINTS-3 => NUMPOINTS >= 5
    for i := 1 to NUMPOINTS - PARAMETERS.C_PTS - PARAMETERS.D_PTS - 3 do
    begin
      p1_x := X[i];
      p1_y := Y[i];
      p2_x := X[i + PARAMETERS.C_PTS + 1];
      p2_y := Y[i + PARAMETERS.C_PTS + 1];
      p3_x := X[i + PARAMETERS.C_PTS + 1 + PARAMETERS.D_PTS + 1];
      p3_y := Y[i + PARAMETERS.C_PTS + 1 + PARAMETERS.D_PTS + 1];

      angle := GetAngle(p1_x, p1_y, p2_x, p2_y, p3_x, p3_y);
      if (angle >= 0) and ((angle < PI_CONST - PARAMETERS.EPSILON) or (angle > PI_CONST + PARAMETERS.EPSILON)) then
      begin
        CMV[10] := true;
        break;
      end;
    end;

  // LIC 11: Three points separated by E_PTS and F_PTS, form triangle area > AREA1.
  CMV[11] := false;
  if NUMPOINTS >= 5 then // E_PTS >= 1, F_PTS >= 1, E_PTS + F_PTS <= NUMPOINTS - 3. Min: 1+1 <= NUMPOINTS-3 => NUMPOINTS >= 5
    for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 3 do
    begin
      p1_x := X[i];
      p1_y := Y[i];
      p2_x := X[i + PARAMETERS.E_PTS + 1];
      p2_y := Y[i + PARAMETERS.E_PTS + 1];
      p3_x := X[i + PARAMETERS.E_PTS + 1 + PARAMETERS.F_PTS + 1];
      p3_y := Y[i + PARAMETERS.E_PTS + 1 + PARAMETERS.F_PTS + 1];

      area := TriangleArea(p1_x, p1_y, p2_x, p2_y, p3_x, p3_y);
      if area > PARAMETERS.AREA1 then
      begin
        CMV[11] := true;
        break;
      end;
    end;

  // LIC 12: Two points separated by G_PTS, X[j] - X[i] < 0.
  CMV[12] := false;
  if NUMPOINTS >= 3 then // G_PTS >= 1, so requires at least 1 + 1 = 2 points plus G_PTS separation.
    for i := 1 to NUMPOINTS - PARAMETERS.G_PTS - 2 do
    begin
      if X[i + PARAMETERS.G_PTS + 1] < X[i] then
      begin
        CMV[12] := true;
        break;
      end;
    end;

  // LIC 13: Two points separated by K_PTS, distance > LENGTH1 AND distance < LENGTH2.
  CMV[13] := false;
  if NUMPOINTS >= 3 then // K_PTS >= 1
    for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 2 do
    begin
      dist := Distance(X[i], Y[i], X[i + PARAMETERS.K_PTS + 1], Y[i + PARAMETERS.K_PTS + 1]);
      if (dist > PARAMETERS.LENGTH1) and (dist < PARAMETERS.LENGTH2) then
      begin
        CMV[13] := true;
        break;
      end;
    end;

  // LIC 14: Three points separated by A_PTS and B_PTS, cannot be contained in RADIUS1 AND can be contained in RADIUS2.
  CMV[14] := false;
  if NUMPOINTS >= 5 then // A_PTS >= 1, B_PTS >= 1
    for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 3 do
    begin
      p1_x := X[i];
      p1_y := Y[i];
      p2_x := X[i + PARAMETERS.A_PTS + 1];
      p2_y := Y[i + PARAMETERS.A_PTS + 1];
      p3_x := X[i + PARAMETERS.A_PTS + 1 + PARAMETERS.B_PTS + 1];
      p3_y := Y[i + PARAMETERS.A_PTS + 1 + PARAMETERS.B_PTS + 1];

      circum_r := Circumradius(p1_x, p1_y, p2_x, p2_y, p3_x, p3_y);
      if (circum_r > PARAMETERS.RADIUS1) and (circum_r <= PARAMETERS.RADIUS2) then
      begin
        CMV[14] := true;
        break;
      end;
    end;

  // LIC 15: Three points separated by E_PTS and F_PTS, area > AREA1 AND area < AREA2.
  CMV[15] := false;
  if NUMPOINTS >= 5 then // E_PTS >= 1, F_PTS >= 1
    for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 3 do
    begin
      p1_x := X[i];
      p1_y := Y[i];
      p2_x := X[i + PARAMETERS.E_PTS + 1];
      p2_y := Y[i + PARAMETERS.E_PTS + 1];
      p3_x := X[i + PARAMETERS.E_PTS + 1 + PARAMETERS.F_PTS + 1];
      p3_y := Y[i + PARAMETERS.E_PTS + 1 + PARAMETERS.F_PTS + 1];

      area := TriangleArea(p1_x, p1_y, p2_x, p2_y, p3_x, p3_y);
      if (area > PARAMETERS.AREA1) and (area < PARAMETERS.AREA2) then
      begin
        CMV[15] := true;
        break;
      end;
    end;

  // --- Compute PUM (Preliminary Unlocking Matrix) ---
  // Based on LCM and CMV
  for i := 1 to 15 do
  begin
    // Diagonal elements: PUM[i, i] is derived from CMV[i]
    // A common interpretation is PUM[i,i] := CMV[i], which is what the FUV calculation implies.
    // If PUM[i,i] is false, FUV[i] is true. If PUM[i,i] is true, then all of row i must be true.
    // So if CMV[i] is false, PUM[i,i] should be false.
    // If CMV[i] is true, PUM[i,i] should be true.
    PUM[i, i] := CMV[i];

    // Off-diagonal elements
    for j := i + 1 to 15 do
    begin
      case LCM[i, j] of
        ANDD:
          begin
            PUM[i, j] := CMV[i] and CMV[j];
            PUM[j, i] := CMV[i] and CMV[j]; // Matrix is symmetric
          end;
        ORR:
          begin
            PUM[i, j] := CMV[i] or CMV[j];
            PUM[j, i] := CMV[i] or CMV[j]; // Matrix is symmetric
          end;
        NOTUSED:
          begin
            PUM[i, j] := true;
            PUM[j, i] := true;
          end;
      end;
    end;
  end;

  // --- Compute FUV (Final Unlocking Vector) ---
  for i := 1 to 15 do
  begin
    if PUM[i, i] = false then
      FUV[i] := true
    else
    begin
      row_all_true := true;
      for j := 1 to 15 do
      begin
        if PUM[i, j] = false then
        begin
          row_all_true := false;
          break;
        end;
      end;
      FUV[i] := row_all_true;
    end;
  end;

  // --- Final Launch Decision ---
  LAUNCH := true;
  for i := 1 to 15 do
  begin
    if FUV[i] = false then
    begin
      LAUNCH := false;
      break;
    end;
  end;

end;

end.
